#include <iostream>
#include <string>
#include <cstdlib>

int main(int argc, char* argv[]) {
    // Validate argument count
    if (argc != 3) {
        std::cout << "Usage: " << argv[0] << " <num1> <num2>" << std::endl;
        return 1;
    }

    try {
        // Convert string arguments to integers
        int num1 = std::stoi(argv[1]);
        int num2 = std::stoi(argv[2]);

        // Calculate and display sum
        int sum = num1 + num2;
        std::cout << "Sum: " << sum << std::endl;

        return 0;
    } catch (const std::invalid_argument& e) {
        std::cout << "Error: Invalid number format" << std::endl;
        return 1;
    }
}

#include <iostream>
#include <unistd.h>
#include <cstdlib>

int main(int argc, char* argv[]) {
    int option;
    bool verbose = false;
    char* outputFile = nullptr;

    // Parse options: -v for verbose, -o for output file
    while ((option = getopt(argc, argv, "vo:")) != -1) {
        switch (option) {
            case 'v':
                verbose = true;
                break;
            case 'o':
                outputFile = optarg;
                break;
            case '?':
                std::cerr << "Usage: " << argv[0] << " [-v] [-o file] <input>" << std::endl;
                return 1;
        }
    }

    // Check for required positional argument
    if (optind >= argc) {
        std::cerr << "Input file required" << std::endl;
        return 1;
    }

    char* inputFile = argv[optind];

    if (verbose) {
        std::cout << "Input: " << inputFile << std::endl;
        if (outputFile) std::cout << "Output: " << outputFile << std::endl;
    }

    std::cout << "Processing file..." << std::endl;
    return 0;
}

#include <iostream>
#include <fstream>
#include <string>

bool isVerboseFlag(const std::string& arg) {
    return arg == "-v" || arg == "--verbose";
}

int main(int argc, char* argv[]) {
    bool verbose = false;
    std::string filename;

    // Parse arguments
    for (int i = 1; i < argc; i++) {
        std::string arg = argv[i];
        if (isVerboseFlag(arg)) {
            verbose = true;
        } else if (filename.empty()) {
            filename = arg;
        }
    }

    // Validate filename
    if (filename.empty()) {
        std::cerr << "Usage: " << argv[0] << " [-v] <filename>" << std::endl;
        return 1;
    }

    // Open and process file
    std::ifstream file(filename);
    if (!file.is_open()) {
        std::cerr << "Error: Cannot open file '" << filename << "'" << std::endl;
        return 1;
    }

    int lines = 0, words = 0, chars = 0;
    std::string word;

    while (std::getline(file, word)) {
        lines++;
        chars += word.length() + 1; // +1 for newline

        // Count words in line
        size_t start = word.find_first_not_of(' \t');
        while (start != std::string::npos) {
            size_t end = word.find_first_of(' \t', start);
            if (end == std::string::npos) end = word.length();
            words++;
            start = word.find_first_not_of(' \t', end);
        }
    }
    file.close();

    // Output results
    if (verbose) {
        std::cout << "File: " << filename << std::endl;
        std::cout << "-------------------" << std::endl;
    }

    std::cout << "Lines: " << lines << std::endl;
    std::cout << "Words: " << words << std::endl;
    std::cout << "Characters: " << chars << std::endl;

    return 0;
}
